window.__QUIZ_DATA__=[{"id":"theory>Biology>2014>PAPER II>PART I>1>a>i","subject":"Biology","year":"2014","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : ORGANIZATION OF LIFE","question":"List three characteristics of living organism","images":[],"marking_scheme":"- Movement/locomotion  - Respiration  - Nutrition/Feeding  - Competition  - Adaptation  - Irritability/sensitivity/response  - Growth/development  - Excretion  - Reproduction  - Life span/death","marks":"3","difficulty":"1"},{"id":"theory>Biology>2014>PAPER II>PART I>1>a>ii","subject":"Biology","year":"2014","type":"Theory","sub_label":"ii","group":"","topic":"CONCEPT OF LIVING : ORGANIZATION OF LIFE","question":"Explain briefly the characteristic  listed in 1(a) above","images":[],"marking_scheme":"Movement  Living things change the position of the whole body/parts of the body; from one place to another; in search of food/shelter/mates, etc.    Excretion  This involves the removal/getting rid of waste products of cell metabolism; metabolic wastes are poison us it allowed to accumulate.    Respiration  This is the breakdown/burning of food substances; by aerobic/anaerobic respiration; to release energy needed for all processes of life.    Reproduction  This is the ability of living organisms to produce new individuals of their own kind; this ensures the continuity of the species of an organism.    Irritability  Response/reaction of organisms; towards changes in the environment; to ensure survival.    Nutrition  The process involved in obtaining/manufacturing food; can be autotrophic/heterotrophic; and utilizing it for growth and maintenance/life processes.    Growth  This is the irreversible increase; in size and weight of an organism; which leads to complexity and maturation    Competition  Ability of organisms to struggle; for all necessity of life; to survive in their environment.    Adaptation  Ability of organisms to adjust; to changes in environment; for survival.    Life span/Death  All living organisms have definite period of existence; all organisms die.","marks":"6","difficulty":"2"},{"id":"theory>Biology>2014>PAPER II>PART I>1>b","subject":"Biology","year":"2014","type":"Theory","sub_label":"b","group":"","topic":"CONCEPT OF LIVING : CLASSIFICATION","question":"In a tabular form state four differences between plants and animals","images":[],"marking_scheme":"Differences between plants and animals    AnimalsPlants- Move from place to place/locomotion; move with the whole body Are fixed/do not move from place to place; and move only parts of the body root/stem/leaves;- Heterotrophic mode of nutrition that depend on already-made food Autotrophic mode of nutrition/manufacture their own food using the energy from the sun;- No chlorophyll/chloroplast Chlorophyll/chloroplast present;- Sense organs present Sense organs absent;- No cell wall Has a cell wall made of cellulose;- Growth is limited/definite; growth in all parts of the body Growth is unlimited/indefinite; growth is apical or terminal;- Store carbohydrate as glycogen Store carbohydrate as starch;- Has special excretory organs No special excretory organs;- Response is fast/short termedResponse very slow/long termed;- Respiratory organs presentNo respiratory organs;","marks":"4","difficulty":"2"},{"id":"theory>Biology>2014>PAPER II>PART I>1>c>i","subject":"Biology","year":"2014","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : CLASSIFICATION","question":"Name one organism that exhibit both plants and animals features","images":[],"marking_scheme":"- Euglena/Chlamydomanas","marks":"1","difficulty":"2"},{"id":"theory>Biology>2014>PAPER II>PART I>1>c>ii","subject":"Biology","year":"2014","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : CLASSIFICATION","question":"Name four animal features and two plant features possessed by the organism named in 1(c)(i) above.","images":[],"marking_scheme":"- Gullet for feeding;  - Has flagellum for locomotion in water;  - Myonemes for movement;  - Has pellicle that gives it a definite shape;  - Has eye spot to detect light intensity;  - Has contractile vacuole for osmoregulation and excretion.    Plant features  - definite shape;  - has chloroplasts containing chlorophyll used to absorb light;  - Paramylum granules;  - Pyrenoid.","marks":"6","difficulty":"3"},{"id":"theory>Biology>2014>PAPER II>PART I>2>a>i","subject":"Biology","year":"2014","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : EXCRETORY SYSTEMS","question":"Define the term elimination","images":[],"marking_scheme":"- Removal of  undigested  food; from the body of living organisms.","marks":"2","difficulty":"1"},{"id":"theory>Biology>2014>PAPER II>PART I>2>a>ii","subject":"Biology","year":"2014","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : EXCRETORY SYSTEMS","question":"Define the term excretion","images":[],"marking_scheme":"- Removal of waste products of  metabolism ; from the cells/tissues of an organisms; may be toxic if retained in the body.","marks":"2","difficulty":"1"},{"id":"theory>Biology>2014>PAPER II>PART I>2>a>iii","subject":"Biology","year":"2014","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : EXCRETORY SYSTEMS","question":"Define the term secretion.","images":[],"marking_scheme":"- Production and releases of substances; useful to the body; by specialised glands of living organisms.","marks":"2","difficulty":"1"},{"id":"theory>Biology>2014>PAPER II>PART I>2>b","subject":"Biology","year":"2014","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"Describe digestion of boiled fish in the gut of humans","images":[],"marking_scheme":"Boiled fish is a source of protein; chewed and swallowed into the stomach; digestion of protein starts from the stomach; stomach secretes gastric juice; containing pepsin, rennin and hydrochloric acid; pepsin in acidic medium acts on the boiled fish and convert it to peptides; peptides move into the duodenum/small intestine; into which pancreatic juice is secreted; undigested protein is acted upon by trypsin in alkaline medium; into peptides/peptones; erepsin finally acts on peptides/peptones in alkaline medium; and converts it into amino acids.","marks":"6","difficulty":"2"},{"id":"theory>Biology>2014>PAPER II>PART I>2>c","subject":"Biology","year":"2014","type":"Theory","sub_label":"c","group":"","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"Make a diagram 8cm - 10cm long of a longitudinal section of a villus and label fully.","images":["data:image/png;base64,"],"marking_scheme":"Label (L)  Epithelium layer, blood capillary, lacteal, lymphatic vessels, goblet cells, venule, arteriole, Crypt of Lieberkuhn, cells of Paneth, Muscularis mucosa.","marks":"8","difficulty":"3"},{"id":"theory>Biology>2014>PAPER II>PART I>3>a>i","subject":"Biology","year":"2014","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM","question":"Explain briefly this ecological term    Biosphere","images":[],"marking_scheme":"- Total/whole area, part of the earth/lithosphere/hydrosphere/water, and atmosphere/air; Inhabitable by living things/where life exists.","marks":"2","difficulty":"1"},{"id":"theory>Biology>2014>PAPER II>PART I>3>a>ii","subject":"Biology","year":"2014","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"Explain briefly this ecological term   Habitat","images":[],"marking_scheme":"- A place/home; within an environment; where an organism naturally lives/dwells","marks":"2","difficulty":"1"},{"id":"theory>Biology>2014>PAPER II>PART I>3>b","subject":"Biology","year":"2014","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : MODES OF NUTRITION","question":"Describe the mode of nutrition in a named carnivorous plant.","images":[],"marking_scheme":"- Carnivorous plants have green leaves and are able to manufacture their own food/carry out photosynthesis;  - they have roots to absorb water and mineral salts from the soil;   - usually grow in places with little nitrogenous salts;  - and use insects/other small animals as source of Nitrogen;  - they have devices/modified leaves with bright colour/scents/sugary liquids/sticky wet surfaces for attracting and trapping insects;  - once the insect is trapped, the plant secretes enzymes to kill and digest it;  - the soluble nitrogenous compounds are absorbed/assimilated by the plant.    Name of Carnivorous Plants  - Butterwort/Pinquicula  - Bladderwort/Utricularia  - Sundew/Drosera  - Venus fly-trap/Dionaea  - Pitcher plants/Nepenthes/Sarracenia.","marks":"6","difficulty":"2"},{"id":"theory>Biology>2014>PAPER II>PART I>3>c","subject":"Biology","year":"2014","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : RELEVANCE OF BIOLOGY TO AGRICULTURE","question":"State three reasons why the dispersal of fruits and seeds are important.","images":[],"marking_scheme":"- Prevents overcrowding of plants;  - Prevents undesirable competition for space/light/water and nutrients;  - Prevents diseases from spreading among plant species;  - Results in colonization of new areas with new plants;  - Results in adaptation to adverse/harsh/unsuitable environment.","marks":"3","difficulty":"2"},{"id":"theory>Biology>2014>PAPER II>PART I>3>d","subject":"Biology","year":"2014","type":"Theory","sub_label":"d","group":"CLOSENESS","topic":"CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS","question":"State six methods of conserving soil.","images":[],"marking_scheme":"- Contour ploughing/ridges are made along the contour of a slopping land/prevent water running down the hill/slope/and washing away soil.  - Strip cultivation/the land is divided into strips along the contours of the slopes/crops are planted in rows that alternate with the strips planted with cover crops/grasses;  - Terracing/construction of terraces which create barriers to hinder rapid water flow down the slope;  - Mulching/materials left after weeding or harvest are left to lie on the soil/protecting the soil against agents of erosion;  - Afforestation/Cover cropping/growing grasses, trees and shrubs to cover and protect the soil;  - Crop rotation/growing crops on a piece of land in sequence/season after season to maintain its fertility;  - Stock drains/construction of barriers/to stop free flow of surface water through farms;  - Application of manure/fertilizer/to stabilize the soil;  - Avoid bush burning;  - Avoid Over grazing.","marks":"6","difficulty":"3"},{"id":"theory>Biology>2014>PAPER II>PART I>4>a>i","subject":"Biology","year":"2014","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS","question":"A survey to determine blood groups was carried out on 250 people living in a community. The result are represented in the table below  Blood groupPercentageA8.0B14.0AB32.8O45.2.    Explain the term co-dominance","images":[],"marking_scheme":"- Codominance occurs when both the alleles in an heterozygous individual are fully expressed; that is both alleles exert their effects so that the hybrid has a phenotype; that is different from what the parents exhibit.","marks":"2","difficulty":"2"},{"id":"theory>Biology>2014>PAPER II>PART I>4>a>ii","subject":"Biology","year":"2014","type":"Theory","sub_label":"ii","group":"FINAL","topic":"BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS","question":"A survey to determine blood groups was carried out on 250 people living in a community. The result are represented in the table below  Blood groupPercentageA8.0B14.0AB32.8O45.2.  Calculate the number of individuals with co-dominance group","images":[],"marking_scheme":"Calculation of Individuals with Co dominant blood group  Mention of codominant blood group is AB    Evidence of Calculation   3.28% of 250    OR     3.28/100 x 250= 82 individuals/people","marks":"3","difficulty":"3"},{"id":"theory>Biology>2014>PAPER II>PART I>4>a>iii","subject":"Biology","year":"2014","type":"Theory","sub_label":"iii","group":"FINAL","topic":"BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS","question":"A survey to determine blood groups was carried out on 250 people living in a community. The result are represented in the table below  Blood groupPercentageA8.0B14.0AB32.8O45.2.  What is the total number of individuals in the table that are able to donate blood to an accident victim of blood group B?","images":[],"marking_scheme":"Total number of individuals that can donate blood to blood group B    The total number of individuals will be from groups B and O  14% of the population is Blood group B  14% of 250    OR  14/100 x 250= 35 individuals/people    45.2% of the population is blood group O  45.2%  of 250    45.2/100 x 250 = 113 individuals/people    - Total number of people = 113 of group O                                                              + 35 of group B  148 individuals/people can donate blood to the accident victim in B    OR  The Total number of individuals from (B and O) blood group B and O             14% + 45.2% = 59.2%                59.2% of 250                59.2/100 x 250/1 = 148 people/individuals","marks":"6","difficulty":"3"},{"id":"theory>Biology>2014>PAPER II>PART I>4>b","subject":"Biology","year":"2014","type":"Theory","sub_label":"b","group":"","topic":"BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS","question":"A man whose blood group is heterozygous A is married to a woman whose blood group is AB. With the aid of genetic diagram, suggest the possible blood groups of their children.","images":["data:image/png;base64,"],"marking_scheme":"Crossing   Possible blood group of their children: AA, AO, AB and BO","marks":"9","difficulty":"3"},{"id":"theory>Biology>2014>PAPER II>PART I>5>a","subject":"Biology","year":"2014","type":"Theory","sub_label":"a","group":"","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"State five precautions that should be taken when using a light microscope","images":[],"marking_scheme":"- Proper handling of the microscope   - Ensure that the lenses are thoroughly clean   - The microscope should be placed about 5cm from the edge of the table.  - Secure the slides with clips  - The objective should not be allowed to touch the cover slip to prevent the danger of crushing the side","marks":"1","difficulty":"1"},{"id":"theory>Biology>2014>PAPER II>PART I>5>b","subject":"Biology","year":"2014","type":"Theory","sub_label":"b","group":"","topic":"CONCEPT OF LIVING : CLASSIFICATION","question":"In a tabular form, outline three differences between Osteichthyes and Chondrichthyes","images":[],"marking_scheme":"Osteichthyes  Chondrichthyes1.Body covered with scales that over lap  Have sharp, tooth like scales that do not overlap2. Have gill cover (operculum)  Have no gill cover, but gill slits 3. Have swim bladder Have no swim bladder 4. Have endoskeleton made of bone. Have endoskeleton made of cartilage Have flexible fins  Have stiff fins","marks":"1","difficulty":"2"},{"id":"theory>Biology>2014>PAPER II>PART I>5>c","subject":"Biology","year":"2014","type":"Theory","sub_label":"c","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"State two reasons why Bryophyte are confined to damp habitat","images":[],"marking_scheme":"- They require water for reproduction: The sperm cell requires water through which it can swim to reach and fertilize the female cell.  - To prevent drying out/desiccation   - Spores require moisture to germinate","marks":"1","difficulty":"1"},{"id":"theory>Biology>2014>PAPER II>PART I>5>d","subject":"Biology","year":"2014","type":"Theory","sub_label":"d","group":"","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"Name three organism that produce by conjugation","images":[],"marking_scheme":"- Spirogyra  - Paramecium  - Mucor","marks":"1","difficulty":"1"},{"id":"theory>Biology>2014>PAPER II>PART I>5>e","subject":"Biology","year":"2014","type":"Theory","sub_label":"e","group":"","topic":"CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS","question":"State three secondary sexual characteristic in girls","images":[],"marking_scheme":"- Sex organs enlarge, ovaries produce eggs and menstrual cycle begins  - Pubic and armpit hair start to grow  - Widening of the hips  - Breast and nipples develop","marks":"1","difficulty":"1"},{"id":"theory>Biology>2014>PAPER II>PART I>5>f>i","subject":"Biology","year":"2014","type":"Theory","sub_label":"i","group":"","topic":"CONCEPT OF LIVING : RESPIRATORY SYSTEM","question":"Name the biological phenomenon use to describe loss of water from plants when transpiration is impossible","images":[],"marking_scheme":"Guttation is the loss of water from plants.","marks":"1","difficulty":"2"},{"id":"theory>Biology>2014>PAPER II>PART I>5>f>ii","subject":"Biology","year":"2014","type":"Theory","sub_label":"ii","group":"","topic":"CONCEPT OF LIVING : REGULATION OF INTERNAL ENVIRONMENT (HOMEOSTASIS)","question":"State two conditions under which the phenomenon named in 5(f)(i)occurs","images":[],"marking_scheme":"- Warm and moist air  - Humid atmosphere.","marks":"1","difficulty":"2"},{"id":"theory>Biology>2014>PAPER II>PART I>5>g","subject":"Biology","year":"2014","type":"Theory","sub_label":"g","group":"","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"State three ways in which photosynthesis is important to the enviroment","images":[],"marking_scheme":"- Production of energy: It is the only means simple inorganic materials are converted into useful energy(glucose) and stored in food.  - It releases oxygen as by-product, used in respiration .  - Removal of carbon dioxide: It uses up large quantities of carbon-dioxide, thereby purifying the air and checking global warming.  - Glucose, a product of photosynthesis is a starting material for the synthesis of proteins, fats, oil and vitamins which serve as food both plant and animals.","marks":"1","difficulty":"1"},{"id":"theory>Biology>2014>PAPER II>PART I>5>h","subject":"Biology","year":"2014","type":"Theory","sub_label":"h","group":"","topic":"MICROORGANISMS: MAN AND HEALTH : TOWARDS BETTER HEALTH","question":"Named three examples of drugs which are commonly abused","images":[],"marking_scheme":"-. Cocaine   - Heroin  - Opium  - Amphetamines","marks":"1","difficulty":"2"},{"id":"theory>Biology>2014>PAPER II>PART I>5>i","subject":"Biology","year":"2014","type":"Theory","sub_label":"i","group":"","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"State two beneficial effect and one harmful effect of bees","images":[],"marking_scheme":"Beneficial effects of Bees to humans  - Production of honey for human consumption  - Pollination of flowers    Harmful effects of Bees to Humans   - Stings","marks":"1","difficulty":"2"},{"id":"theory>Biology>2014>PAPER II>PART III>6>a","subject":"Biology","year":"2014","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"State 5 reasons why animals move from place to place.","images":[],"marking_scheme":"- To search for food; escape predators; find mates for reproduction; to disperse/reduce competition/overcrowding by moving to new locations; avoid dangers; find new and favourable habitats.","marks":"5","difficulty":"1"},{"id":"theory>Biology>2014>PAPER II>PART III>6>b>i","subject":"Biology","year":"2014","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : ORGANIZATION OF LIFE","question":"State one function each of the following structures found in plants: epidermis","images":[],"marking_scheme":"- Epidermis: for protection of inner cells from injury, infection; prevent excessive loss of water.","marks":"1","difficulty":"1"},{"id":"theory>Biology>2014>PAPER II>PART III>6>b>ii","subject":"Biology","year":"2014","type":"Theory","sub_label":"ii","group":"","topic":"CONCEPT OF LIVING : ORGANIZATION OF LIFE","question":"State one function each of the following structures found in plants: Phloem","images":[],"marking_scheme":"- Phloem: responsible for the transportation of enzymes/hormones; manufactured food.","marks":"1","difficulty":"1"},{"id":"theory>Biology>2014>PAPER II>PART III>6>b>iii","subject":"Biology","year":"2014","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : ORGANIZATION OF LIFE","question":"State one function each of the following structures found in plants: Sclerenchyma","images":[],"marking_scheme":"- Sclerenchyma: strengthens the stem/provide mechanical support; makes plants flexible.","marks":"1","difficulty":"1"},{"id":"theory>Biology>2014>PAPER II>PART III>6>c>i","subject":"Biology","year":"2014","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ECOLOGICAL MANAGEMENT : BIOLOGICAL ASSOCIATIONS","question":"Give 2 examples each of the following types of organisms  - Parasitic Plants","images":[],"marking_scheme":"- Viscum/Mistletoe; dodder plant/Cassytha;; Cuscuta;Phytophthor; Peronospora","marks":"2","difficulty":"2"},{"id":"theory>Biology>2014>PAPER II>PART III>6>c>ii","subject":"Biology","year":"2014","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ECOLOGICAL MANAGEMENT : BIOLOGICAL ASSOCIATIONS","question":"Give 2 examples each of the following types of organisms  - Saprophytes","images":[],"marking_scheme":"- Bacteria; fungi/Rhizopus, Mucor, Aspergillus; Mushroom/Agaricus","marks":"2","difficulty":"2"},{"id":"theory>Biology>2014>PAPER II>PART III>6>d","subject":"Biology","year":"2014","type":"Theory","sub_label":"d","group":"CLOSENESS","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"State two adaptive features of plants which inhabit salt water swamp","images":[],"marking_scheme":"- succulent stem/root/store water; to silute the salt;  - presence of pneumatophores/breathing roots; for breathing atmospheric air/oxygen;  - presence of stilt roots; for anchorage;  - viviparous seedling; to ensure their survival/continuity;  - some secrete excess salt into swamps; to maintain balance of body salt.","marks":"4","difficulty":"2"},{"id":"theory>Biology>2014>PAPER II>PART III>6>e>i","subject":"Biology","year":"2014","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ECOLOGY OF POPULATION : FACTORS THAT AFFECT POPULATION","question":"State two factors each which result in increase in population density","images":[],"marking_scheme":"- Increase population density: Increased birth rate/natality; immigration; increase in food availability; low mortality rate.","marks":"2","difficulty":"2"},{"id":"theory>Biology>2014>PAPER II>PART III>6>e>ii","subject":"Biology","year":"2014","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ECOLOGY OF POPULATION : FACTORS THAT AFFECT POPULATION","question":"State two factors each which result in increase in population density","images":[],"marking_scheme":"- emigration; diseases; drought/famine/natural disaster; high mortality rate; low natality rate.","marks":"2","difficulty":"2"},{"id":"theory>Biology>2014>PAPER II>PART III>6>f","subject":"Biology","year":"2014","type":"Theory","sub_label":"f","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : RELEVANCE OF BIOLOGY TO AGRICULTURE","question":"Mention four ways in which modern agricultural activities may threaten the survival of species.","images":[],"marking_scheme":"- Deforestation/commercial farming destroys habitats of species;  - Destruction/loss of natural vegetation/habitat;  - Over hunting of games reduces population of species;  - Improper/Indiscriminate application of chemical/sanitization/eutrophication/pesticides destroys species;  - Lack of afforestation practices;  - Inappropriate fishing methods threaten the population of fish","marks":"4","difficulty":"3"},{"id":"theory>Biology>2014>PAPER II>PART III>6>g","subject":"Biology","year":"2014","type":"Theory","sub_label":"g","group":"CLOSENESS","topic":"CONCEPT OF LIVING : CELL THEORY","question":"State three reasons why Mitosis is important to living organisms.","images":[],"marking_scheme":"- It ensures growth;  - Involved asexual reproduction e.g. fission, building, spore formation;  - Ensures retention of diploid condition;  - Repair of tissues within organisms;  - Transfer of exact genetic code from parents to offspring.","marks":"3","difficulty":"3"},{"id":"theory>Biology>2014>PAPER II>PART III>6>h","subject":"Biology","year":"2014","type":"Theory","sub_label":"h","group":"CLOSENESS","topic":"ECOLOGY OF POPULATION : PRESERVATION AND STORAGE OF FOODS","question":"State three causes of food spoilage","images":[],"marking_scheme":"- Microbial attacks by bacteria of fungi/or saprophytic action;  - Pest attack by beetles, weevils that destroy stored grains;  - Improper storage which results in deterioration and spoilage of stored foods;  - Destruction of stored fruits and meat by some worms, usually larva of flies;  - Delay in transportation due to bad roads;  - Lack of market facilities for the commodity;  - Poor harvesting method/damage to fruits/vegetables/tubers during harvesting;  - Poor unhygienic handling/processing/exposure to dust;  - Storage in contaminated containers;  - Use of contaminated water to wash food.","marks":"3","difficulty":"1"}];